}

.register-row .value {
    color: var(--success);
}

.register-row .perms {
    color: var(--text-secondary);
    font-size: 0.85rem;
}

.register-row.null .value {
    color: var(--text-secondary);
}

.register-row.has-clist {
    cursor: pointer;
    border-left: 2px solid var(--accent);
}

.register-row.has-clist:hover {
    background: var(--bg-tertiary);
}

.state-info {
    display: flex;
    flex-direction: column;
    gap: 0.3rem;
}

.state-row {
    display: flex;
    justify-content: space-between;
    padding: 0.35rem 0.5rem;
    background: var(--bg-input);
    border-radius: 4px;
    font-size: 0.85rem;
}

.state-row .label {
    color: var(--text-secondary);
}

.state-row .value {
    color: var(--success);
    font-family: 'Consolas', monospace;
}

.state-row.clickable {
    cursor: pointer;
    transition: background 0.2s ease, border-left 0.2s ease;
    border-left: 3px solid transparent;
}

.state-row.clickable:hover {
    background: var(--bg-panel);
    border-left: 3px solid var(--accent);
}

.state-row.clickable:hover .value {
    color: var(--accent);
}

.boot-sequence {
    margin-top: 1.5rem;
    padding-top: 1rem;
    border-top: 1px solid var(--border);
}

.boot-sequence h3 {
    color: var(--warning);
    font-size: 0.9rem;
    margin-bottom: 0.8rem;
}

.boot-steps {
    display: flex;
    flex-direction: column;
    gap: 0.4rem;
}

.boot-step {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.4rem 0.6rem;
    background: var(--bg-input);
    border-radius: 4px;
    font-size: 0.8rem;
    color: var(--text-secondary);
    border-left: 3px solid var(--border);
    transition: all 0.3s;
}

.boot-step span {
    width: 20px;
    height: 20px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: var(--border);
    border-radius: 50%;
    font-size: 0.7rem;
    font-weight: bold;
}

.boot-step.active {
    color: var(--text-primary);
    border-left-color: var(--accent);
    background: rgba(168, 85, 247, 0.15);
}

.boot-step.active span {
    background: var(--accent);
    color: #1a1a2e;
}

.boot-step.done {
    color: var(--success);
    border-left-color: var(--success);
}

.boot-step.done span {
    background: var(--success);
    color: #1a1a2e;
}

.boot-status {
    margin-top: 0.8rem;
    padding: 0.5rem;
    background: var(--bg-dark);
    border-radius: 4px;
    font-size: 0.8rem;
    color: var(--text-secondary);
    text-align: center;
}

.boot-sequence-banner {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding: 0.5rem 0.8rem;
    background: var(--bg-panel);
    border-radius: 6px;
    border: 1px solid var(--border);
    margin-bottom: 0.6rem;
    flex-wrap: wrap;
    overflow: visible;
}

.boot-steps-horizontal {
    display: flex;
    gap: 0.4rem;
    flex: 1;
    overflow: visible;
}

.boot-label {
    color: var(--warning);
    font-weight: 600;
    font-size: 0.8rem;
}

.boot-step-btn {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    padding: 0.35rem 0.6rem;
    background: var(--bg-input);
    color: var(--text-secondary);
    border: 1px solid var(--border);
    border-radius: 4px;
    font-size: 0.75rem;
    cursor: pointer;
    transition: all 0.2s;
    flex: 1;
    justify-content: center;
}

.boot-step-btn span {
    width: 18px;
    height: 18px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: var(--border);
    border-radius: 50%;
    font-size: 0.7rem;
    font-weight: bold;
    color: var(--text-secondary);
}

.boot-step-btn:hover:not(.done):not(:disabled) {
