    border-color: var(--accent);
    color: var(--text-primary);
}

.boot-step-btn.active {
    background: rgba(233, 69, 96, 0.2);
    border-color: var(--accent);
    color: var(--text-primary);
}

.boot-step-btn.active span {
    background: var(--accent);
