}

.clist-tab-perms {
    display: flex;
    gap: 2px;
}

.clist-tab-perms .perm-badge {
    font-size: 0.65rem;
    padding: 0.1rem 0.25rem;
}

.clist-tab-offset {
    color: var(--text-secondary);
    font-size: 0.75rem;
    min-width: 3.5rem;
    text-align: right;
}

.clist-tab-entry-wrap {
    display: flex;
    flex-direction: column;
}

.clist-tab-expand {
