}

.clist-tab-entry-wrap.expanded .clist-tab-words {
    display: flex;
}

.clist-tab-entry-wrap.expanded .clist-tab-entry {
    border-radius: 4px 4px 0 0;
}

.clist-word {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    font-size: 0.7rem;
    font-family: var(--font-mono);
}

.clist-word-label {
    color: var(--accent);
    font-weight: 600;
    min-width: 1.5rem;
}

.clist-word-desc {
    color: var(--text-secondary);
    min-width: 4rem;
}

.clist-word-val {
    color: var(--text-primary);
    font-weight: 500;
}

.content-tab-section {
    padding: 0.5rem;
}

.content-tab-heading {
    color: var(--accent);
    font-weight: 600;
    font-size: 0.85rem;
    margin-bottom: 0.5rem;
    font-family: var(--font-mono);
}

.content-tab-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 0.3rem;
    margin-bottom: 0.5rem;
}

.content-tab-field {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    padding: 0.25rem 0.4rem;
    background: var(--bg-input);
    border-radius: 4px;
    border: 1px solid var(--border);
    font-size: 0.8rem;
    font-family: var(--font-mono);
}

.content-tab-key {
    color: var(--text-secondary);
    font-size: 0.7rem;
    min-width: 2.5rem;
}

.content-tab-val {
    color: var(--text-primary);
    font-weight: 500;
}

.content-tab-desc {
    color: var(--text-secondary);
