    border: 1px solid var(--border);
    color: var(--text-primary);
    padding: 0.4rem 0.8rem;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.75rem;
    transition: all 0.2s;
}

.btn-recalc:hover {
    background: var(--accent);
    border-color: var(--accent);
}

.permission-legend {
    background: var(--bg-panel);
    border-radius: 8px;
    padding: 1.2rem;
    border: 1px solid var(--border);
}

.permission-legend h3 {
    color: var(--accent);
    margin-bottom: 1rem;
    font-size: 1rem;
}

.perm-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
    gap: 0.8rem;
}

.perm-item {
    display: flex;
    align-items: center;
    gap: 0.8rem;
    background: var(--bg-input);
    padding: 0.8rem;
    border-radius: 6px;
}

.perm-item .perm-badge {
    width: 36px;
    height: 36px;
    font-size: 1rem;
    flex-shrink: 0;
}

.perm-info {
    display: flex;
    flex-direction: column;
}

.perm-info strong {
    color: var(--text-primary);
}

.perm-info span {
    color: var(--text-secondary);
    font-size: 0.8rem;
}

.btn-create {
    width: 100%;
    margin-top: 1rem;
    background: var(--success);
    color: #1a1a2e;
}

.lock-indicator {
    display: flex;
    align-items: center;
    gap: 0.3rem;
    font-size: 0.75rem;
    color: var(--warning);
}

/* ==================== CAPABILITY DNS EDITOR ==================== */

.dns-layout {
    display: grid;
    grid-template-columns: 1fr 1fr;
    grid-template-rows: 1fr auto;
    gap: 1.5rem;
    min-height: calc(100vh - 200px);
}

.dns-panel {
    background: var(--bg-panel);
    border-radius: 8px;
    padding: 1.5rem;
    border: 1px solid var(--border);
}

.dns-panel h2 {
    color: var(--accent);
    margin-bottom: 0.5rem;
}

.dns-panel h3 {
    color: var(--warning);
    margin-bottom: 0.8rem;
}

.dns-intro {
    color: var(--text-secondary);
    font-size: 0.85rem;
    margin-bottom: 1.5rem;
}

.dns-log {
    grid-column: 1 / -1;
}


.preview-empty {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 200px;
    color: var(--text-secondary);
    border: 2px dashed var(--border);
    border-radius: 8px;
}

.preview-token {
    background: linear-gradient(135deg, #d4af37, #aa8c2c);
    border-radius: 12px;
    padding: 1.5rem;
    text-align: center;
    box-shadow: 0 4px 20px rgba(212, 175, 55, 0.3);
}

.preview-token-header {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 0.5rem;
    margin-bottom: 0.8rem;
}

.preview-token-icon {
    font-size: 1.5rem;
}

.preview-token-name {
    color: #1a1a2e;
    font-weight: bold;
    font-size: 1.2rem;
}

.preview-token-key {
    font-family: 'Consolas', monospace;
    font-size: 0.7rem;
    color: #1a1a2e;
    opacity: 0.8;
    word-break: break-all;
    margin-bottom: 1rem;
    padding: 0.5rem;
    background: rgba(0, 0, 0, 0.1);
    border-radius: 4px;
}

.preview-token-perms {
    display: flex;
    justify-content: center;
    gap: 0.3rem;
    flex-wrap: wrap;
}

.preview-perm {
    padding: 0.3rem 0.5rem;
    background: rgba(0, 0, 0, 0.2);
    border-radius: 4px;
    color: #1a1a2e;
    font-weight: bold;
    font-size: 0.85rem;
}

.preview-token-target {
    margin-top: 1rem;
    padding-top: 0.8rem;
    border-top: 1px solid rgba(0, 0, 0, 0.2);
    color: #1a1a2e;
    font-size: 0.85rem;
}

.dns-registry {
    margin-top: 1.5rem;
    padding-top: 1.5rem;
    border-top: 1px solid var(--border);
}

.registry-list {
    max-height: 200px;
    overflow-y: auto;
}

.registry-empty {
    color: var(--text-secondary);
    font-style: italic;
    padding: 1rem;
    text-align: center;
}

.registry-item {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.6rem 0.8rem;
    background: var(--bg-input);
    border-radius: 4px;
    margin-bottom: 0.5rem;
    border-left: 3px solid var(--warning);
}

.registry-item-name {
    font-weight: bold;
    color: var(--text-primary);
}

.registry-item-perms {
    display: flex;
    gap: 0.2rem;
}

.registry-item-perm {
    padding: 0.15rem 0.4rem;
    background: var(--bg-panel);
    border-radius: 3px;
    font-size: 0.75rem;
    font-weight: bold;
}

.dns-log-output {
    max-height: 150px;
    overflow-y: auto;
    font-family: 'Consolas', monospace;
    font-size: 0.85rem;
    background: var(--bg-dark);
    border-radius: 4px;
    padding: 0.8rem;
}

.dns-log-output .log-entry {
    margin-bottom: 0.3rem;
    padding: 0.3rem 0;
    border-bottom: 1px solid var(--border);
}

.dns-log-output .log-entry:last-child {
    border-bottom: none;
}

/* ==================== INTERACTIVE TUTORIAL ==================== */

.tutorial-layout {
    display: flex;
    flex-direction: column;
    height: 100%;
    gap: 0;
}

.tutorial-nav-bar {
    display: flex;
    align-items: center;
    gap: 1rem;
    padding: 0.5rem 1rem;
    background: var(--bg-panel);
    border-radius: 6px;
    margin-bottom: 0.8rem;
    flex-shrink: 0;
}

.tutorial-nav-bar select {
    padding: 0.4rem 0.8rem;
    background: var(--bg-input);
    color: var(--text-primary);
    border: 1px solid var(--border);
    border-radius: 4px;
    font-size: 0.85rem;
}

.progress-mini {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    margin-left: auto;
}

.progress-bar-mini {
    width: 80px;
    height: 6px;
    background: var(--bg-input);
    border-radius: 3px;
    overflow: hidden;
}

.progress-mini .progress-fill {
    height: 100%;
    background: linear-gradient(90deg, var(--accent), var(--success));
    transition: width 0.3s ease;
}

.progress-mini span {
    color: var(--text-secondary);
    font-size: 0.75rem;
}

.tutorial-sidebar {
    display: none;
}

.lesson-list {
    display: none;
}

.lesson-btn {
    display: none;
}

.tutorial-progress {
    display: none;
}

.progress-bar {
    height: 8px;
    background: var(--bg-input);
    border-radius: 4px;
    overflow: hidden;
    margin-bottom: 0.5rem;
}

.progress-fill {
    height: 100%;
    background: linear-gradient(90deg, var(--accent), var(--success));
    transition: width 0.3s ease;
}

.progress-text {
    color: var(--text-secondary);
    font-size: 0.8rem;
}

.tutorial-main {
    background: var(--bg-panel);
    border-radius: 8px;
    flex: 1;
    overflow-y: auto;
    padding: 1.5rem;
    border: 1px solid var(--border);
    display: flex;
    flex-direction: column;
}

.lesson-header {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding-bottom: 0.5rem;
    border-bottom: 1px solid var(--border);
    margin-bottom: 1rem;
    flex-wrap: nowrap;
}

.btn-back-to-landing {
    background: var(--bg-panel);
    color: var(--accent);
    border: 1px solid var(--accent);
    padding: 0.5rem 1rem;
    border-radius: 6px;
    cursor: pointer;
    font-weight: 600;
    transition: all 0.2s ease;
}

.btn-back-to-landing:hover {
    background: var(--accent);
    color: white;
}

.lesson-dropdown {
    position: relative;
    flex: 1;
    min-width: 0;
}

.lesson-dropdown-trigger {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    cursor: pointer;
    padding: 0.3rem 0.5rem;
    border-radius: 4px;
    transition: background 0.15s;
}

.lesson-dropdown-trigger:hover {
    background: var(--bg-tertiary);
}

#lessonDropdownLabel {
    font-size: 0.85rem;
    font-weight: bold;
    color: var(--accent);
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.lesson-dropdown-arrow {
    font-size: 0.65rem;
    color: var(--text-secondary);
    flex-shrink: 0;
}

.lesson-dropdown-menu {
    display: none;
    position: absolute;
    top: 100%;
    left: 0;
    z-index: 100;
    background: var(--bg-panel);
    border: 1px solid var(--border);
    border-radius: 6px;
    box-shadow: 0 4px 16px rgba(0,0,0,0.4);
    min-width: 220px;
    max-height: 70vh;
    overflow-y: auto;
    padding: 0.3rem 0;
}

.lesson-dropdown.open .lesson-dropdown-menu {
    display: block;
}

.lesson-dropdown-group-label {
    font-size: 0.7rem;
    font-weight: bold;
    color: var(--accent);
    padding: 0.5rem 0.8rem 0.25rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: space-between;
}


.lesson-dropdown-items {
    display: none;
}

.lesson-dropdown-group:hover .lesson-dropdown-items,
.lesson-dropdown-group.expanded .lesson-dropdown-items {
    display: block;
}

.lesson-dropdown-item {
    font-size: 0.75rem;
    padding: 0.35rem 0.8rem 0.35rem 1.4rem;
    cursor: pointer;
    color: var(--text-primary);
    transition: background 0.1s;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.lesson-dropdown-item:hover {
    background: var(--bg-tertiary);
    color: var(--accent);
}

.lesson-dropdown-item.active {
    color: var(--accent);
    font-weight: bold;
}

.lesson-step-nav-bottom {
    margin-top: 1.5rem;
    padding-top: 1rem;
    border-top: 1px solid var(--border);
}

.lesson-content {
    flex: 1;
    overflow-y: auto;
}

.lesson-text {
    line-height: 1.7;
    margin-bottom: 1.5rem;
}

.lesson-text h3 {
    color: var(--warning);
    margin-bottom: 0.8rem;
}

.lesson-text p {
    color: var(--text-primary);
    margin-bottom: 1rem;
}

.lesson-text ul {
    margin-left: 1.5rem;
    margin-bottom: 1rem;
}

.lesson-text li {
    color: var(--text-primary);
    margin-bottom: 0.5rem;
}

.lesson-text code {
    background: var(--bg-input);
    padding: 0.2rem 0.5rem;
    border-radius: 4px;
    font-family: 'Consolas', monospace;
    color: var(--success);
}

.lesson-text .highlight {
    background: rgba(233, 69, 96, 0.2);
    border-left: 3px solid var(--accent);
    padding: 1rem;
    margin: 1rem 0;
    border-radius: 0 6px 6px 0;
}

.lesson-text .key-concept {
    background: rgba(74, 222, 128, 0.1);
    border: 1px solid var(--success);
    padding: 1rem;
    border-radius: 6px;
    margin: 1rem 0;
}

.lesson-demo {
    background: var(--bg-dark);
    border-radius: 8px;
    padding: 1.5rem;
    margin-bottom: 1.5rem;
    border: 1px solid var(--border);
}

.demo-title {
    color: var(--warning);
    font-size: 0.9rem;
    margin-bottom: 1rem;
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.demo-content {
    display: flex;
    gap: 2rem;
    align-items: flex-start;
}

.demo-visual {
    flex: 1;
}

.demo-explanation {
    flex: 1;
    color: var(--text-secondary);
    font-size: 0.9rem;
    line-height: 1.6;
}

.golden-token-demo {
    background: linear-gradient(135deg, #d4af37, #aa8c2c);
    border-radius: 8px;
    padding: 1.5rem;
    text-align: center;
    box-shadow: 0 4px 20px rgba(212, 175, 55, 0.3);
}

.token-label {
    color: #1a1a2e;
    font-weight: bold;
    font-size: 0.9rem;
    margin-bottom: 0.5rem;
}

.token-key {
    font-family: 'Consolas', monospace;
    font-size: 0.65rem;
    color: #1a1a2e;
    word-break: break-all;
    opacity: 0.8;
}

.permission-demo {
    display: flex;
    flex-wrap: wrap;
    gap: 0.5rem;
    margin-top: 1rem;
}

.perm-demo-badge {
    padding: 0.4rem 0.8rem;
    border-radius: 4px;
    font-weight: bold;
    font-size: 0.85rem;
}

.lesson-interactive {
    background: var(--bg-input);
    border-radius: 8px;
    padding: 1.5rem;
    border: 1px solid var(--border);
}

.interactive-title {
    color: var(--accent);
    font-size: 0.95rem;
    margin-bottom: 1rem;
}

.quiz-question {
    color: var(--text-primary);
    margin-bottom: 1rem;
}

.quiz-options {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.quiz-option {
    padding: 0.8rem 1rem;
    background: var(--bg-dark);
    border: 1px solid var(--border);
    border-radius: 6px;
    cursor: pointer;
    color: var(--text-primary);
    text-align: left;
    transition: all 0.2s;
}

.quiz-option:hover {
    border-color: var(--accent);
}

.quiz-option.correct {
    border-color: var(--success);
    background: rgba(74, 222, 128, 0.1);
}

.quiz-option.incorrect {
    border-color: var(--error);
    background: rgba(248, 113, 113, 0.1);
}

.quiz-feedback {
    margin-top: 1rem;
    padding: 0.8rem;
    border-radius: 6px;
    font-size: 0.9rem;
}

.quiz-feedback.correct {
    background: rgba(74, 222, 128, 0.15);
    color: var(--success);
}

.quiz-feedback.incorrect {
    background: rgba(248, 113, 113, 0.15);
    color: var(--error);
}

.lesson-step-nav {
    display: flex;
    justify-content: center;
    align-items: center;
    gap: 1rem;
    padding: 0;
    margin-left: auto;
}

.lesson-step-nav .btn-step {
    padding: 0.5rem 1rem;
    background: var(--bg-tertiary);
    border: 1px solid var(--border);
    color: var(--text);
    border-radius: 6px;
    cursor: pointer;
    transition: all 0.2s;
}

.lesson-step-nav .btn-step:hover:not(:disabled) {
    background: var(--accent);
    color: #1a1a2e;
    border-color: var(--accent);
}

.lesson-step-nav .btn-step:disabled {
    opacity: 0.4;
    cursor: not-allowed;
}

.step-indicator {
    color: var(--text-muted);
    font-size: 0.9rem;
    min-width: 100px;
    text-align: center;
}

.lesson-footer {
    display: flex;
    justify-content: flex-end;
    gap: 1rem;
    padding-top: 1rem;
    border-top: 1px solid var(--border);
    margin-top: 1rem;
}

.tutorial-edit-buttons {
    display: flex;
    gap: 0.5rem;
}

.btn-try {
    padding: 0.6rem 1.2rem;
    background: var(--bg-input);
    border: 1px solid var(--accent);
    border-radius: 4px;
    color: var(--accent);
    cursor: pointer;
    transition: all 0.2s;
}

.btn-try:hover {
    background: var(--accent);
    color: white;
}

.btn-complete {
    padding: 0.6rem 1.2rem;
    background: var(--success);
    border: none;
    border-radius: 4px;
    color: var(--bg-dark);
    font-weight: bold;
    cursor: pointer;
    transition: all 0.2s;
}

.btn-complete:hover {
    opacity: 0.9;
}

.register-demo {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 0.5rem;
}

.reg-demo-item {
    background: var(--bg-panel);
    padding: 0.6rem;
    border-radius: 4px;
    display: flex;
    justify-content: space-between;
    font-family: 'Consolas', monospace;
    font-size: 0.85rem;
}

.reg-demo-name {
    color: var(--success);
}

.reg-demo-value {
    color: var(--text-secondary);
}

/* ==================== INSTRUCTION VISUALIZER ==================== */

.visualizer-layout {
    display: grid;
    grid-template-columns: 300px 1fr;
    gap: 1.5rem;
    min-height: calc(100vh - 200px);
}

.viz-controls {
    background: var(--bg-panel);
    border-radius: 8px;
    padding: 1.5rem;
    border: 1px solid var(--border);
}

.viz-controls h2 {
    color: var(--accent);
    margin-bottom: 0.5rem;
}

.viz-intro {
    color: var(--text-secondary);
    font-size: 0.85rem;
    margin-bottom: 1.5rem;
}

.viz-instruction-select {
    margin-bottom: 1rem;
}

.viz-instruction-select label {
    display: block;
    color: var(--text-secondary);
    font-size: 0.85rem;
    margin-bottom: 0.3rem;
}

.viz-instruction-select select {
    width: 100%;
    padding: 0.6rem;
    background: var(--bg-input);
    border: 1px solid var(--border);
    border-radius: 6px;
    color: var(--text-primary);
    font-size: 0.95rem;
}

.viz-operands {
    margin-bottom: 1rem;
}

.viz-operand-row {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    margin-bottom: 0.5rem;
}

.viz-operand-row label {
    flex: 1;
    color: var(--text-secondary);
    font-size: 0.85rem;
}

.viz-operand-row input {
    width: 80px;
    padding: 0.5rem;
    background: var(--bg-input);
    border: 1px solid var(--border);
    border-radius: 4px;
    color: var(--text-primary);
    text-align: center;
}

.viz-buttons {
    display: flex;
    gap: 0.5rem;
    flex-wrap: wrap;
}

.viz-buttons .btn {
    flex: 1;
    min-width: 80px;
}

.btn-setup { background: var(--accent); color: #1a1a2e; }
.btn-run { background: var(--success); color: #1a1a2e; }
.btn-run:disabled { background: #555; color: #999; cursor: not-allowed; }
.btn-reset { background: var(--warning); color: #1a1a2e; }

.viz-stage {
    display: flex;
    flex-direction: column;
    gap: 1.5rem;
}

.viz-registers {
    display: flex;
    justify-content: space-around;
    align-items: center;
    background: var(--bg-panel);
    border-radius: 8px;
    padding: 2rem;
    border: 1px solid var(--border);
    min-height: 250px;
}

.viz-reg-column h3 {
    color: var(--text-secondary);
    font-size: 0.85rem;
    text-align: center;
    margin-bottom: 1rem;
}

.viz-reg-box {
    background: var(--bg-input);
    border: 2px solid var(--border);
    border-radius: 8px;
    padding: 1rem 1.5rem;
    text-align: center;
    margin-bottom: 0.8rem;
    transition: all 0.3s ease;
}

.viz-reg-box.active {
    border-color: var(--accent);
    box-shadow: 0 0 20px var(--accent-glow);
}

.viz-reg-box.highlight {
    border-color: var(--success);
    box-shadow: 0 0 20px rgba(16, 185, 129, 0.5);
}

.viz-reg-box.viz-dest {
    border-color: var(--warning);
}

.viz-reg-label {
    font-size: 0.85rem;
    color: var(--text-secondary);
    margin-bottom: 0.3rem;
}

.viz-reg-value {
    font-family: 'Consolas', monospace;
    font-size: 1.1rem;
    color: var(--success);
}

.viz-alu {
    display: flex;
    flex-direction: column;
    align-items: center;
}

.viz-alu-box {
    background: linear-gradient(135deg, var(--accent) 0%, #7c3aed 100%);
    border-radius: 12px;
    padding: 1.5rem 2rem;
    text-align: center;
    min-width: 120px;
}

.viz-alu-op {
    font-size: 1.5rem;
    font-weight: bold;
    color: white;
    margin-bottom: 0.5rem;
}

.viz-alu-result {
    font-family: 'Consolas', monospace;
    font-size: 0.9rem;
    color: rgba(255,255,255,0.9);
}

.viz-data-flow {
    margin-top: 1rem;
    font-size: 2rem;
    color: var(--accent);
    opacity: 0;
    transition: opacity 0.3s;
}

.viz-data-flow.show {
    opacity: 1;
    animation: pulse 0.5s ease-in-out infinite;
}

@keyframes pulse {
    0%, 100% { transform: scale(1); }
    50% { transform: scale(1.2); }
}

.viz-flags-panel {
    background: var(--bg-panel);
    border-radius: 8px;
    padding: 1.5rem;
    border: 1px solid var(--border);
}

.viz-flags-panel h3 {
    color: var(--text-secondary);
    font-size: 0.9rem;
    margin-bottom: 1rem;
}

.viz-flags {
    display: flex;
    justify-content: center;
    gap: 2rem;
}

.viz-flag {
    text-align: center;
    padding: 1rem;
    background: var(--bg-input);
    border-radius: 8px;
    border: 2px solid var(--border);
    min-width: 80px;
    transition: all 0.3s;
}

.viz-flag span {
    display: block;
    font-size: 1.5rem;
    font-weight: bold;
    color: var(--text-secondary);
}

.viz-flag.active span {
    color: var(--success);
}

.viz-flag.active {
    border-color: var(--success);
    box-shadow: 0 0 15px rgba(16, 185, 129, 0.4);
}

.viz-flag.changed {
    animation: flagPulse 0.5s ease-in-out;
}

@keyframes flagPulse {
    0%, 100% { transform: scale(1); }
    50% { transform: scale(1.15); background: var(--success); }
}

.viz-flag-desc {
    font-size: 0.75rem;
    color: var(--text-secondary);
    margin-top: 0.3rem;
}

.viz-explanation {
    background: var(--bg-panel);
    border-radius: 8px;
    padding: 1.5rem;
    border: 1px solid var(--border);
}

.viz-explanation h3 {
    color: var(--accent);
    margin-bottom: 1rem;
}

.viz-steps {
    font-size: 0.95rem;
    line-height: 1.8;
}

.viz-step {
    padding: 0.8rem;
    margin-bottom: 0.5rem;
    background: var(--bg-input);
    border-radius: 6px;
    border-left: 3px solid var(--border);
    opacity: 0.5;
    transition: all 0.3s;
}

.viz-step.active {
    opacity: 1;
    border-left-color: var(--accent);
}

.viz-step.done {
    opacity: 1;
    border-left-color: var(--success);
}

.viz-step-num {
    display: inline-block;
    width: 24px;
    height: 24px;
    background: var(--border);
    border-radius: 50%;
    text-align: center;
    line-height: 24px;
    font-size: 0.8rem;
    margin-right: 0.5rem;
}

.viz-step.active .viz-step-num {
    background: var(--accent);
    color: #1a1a2e;
}

.viz-step.done .viz-step-num {
    background: var(--success);
    color: #1a1a2e;
}

.viz-hint {
    color: var(--text-secondary);
    font-style: italic;
}

@media (max-width: 900px) {
    .visualizer-layout {
        grid-template-columns: 1fr;
    }

    .viz-registers {
        flex-direction: column;
        gap: 1.5rem;
    }
}

@media (max-width: 900px) {
    .capabilities-layout {
        grid-template-columns: 1fr;
    }

    .cap-sidebar {
        max-height: none;
    }
}

/* Mobile header - horizontal scroll for view buttons */
@media (max-width: 600px) {
    header {
        flex-wrap: nowrap;
        gap: 0.5rem;
        padding: 0.4rem 0.5rem;
    }

    header h1 {
        font-size: 0.9rem;
    }

    .header-left {
