    }

    .header-right {
        display: none;
    }

    nav.controls {
        flex: 1;
        min-width: 0;
        overflow: hidden;
    }

    .view-buttons {
        justify-content: flex-start;
        padding: 0.25rem 0;
    }

    .btn-view {
        padding: 0.3rem 0.5rem;
        font-size: 0.75rem;
    }

    .btn-back {
        padding: 0.3rem 0.5rem;
        font-size: 0.75rem;
    }
}

