    padding: 10px 12px;
    border-bottom: 1px solid var(--border);
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

.hp35-trace-list {
    overflow-y: auto;
    padding: 4px 0;
    flex: 1;
}

.hp35-trace-entry {
    padding: 6px 12px;
    border-bottom: 1px solid rgba(45,55,72,0.4);
}

.hp35-trace-latest {
    background: rgba(233,69,96,0.08);
}

.hp35-trace-lambda {
    font-family: 'Courier New', monospace;
    font-size: 0.72rem;
    color: #88ccff;
    word-break: break-all;
    line-height: 1.3;
}

.hp35-trace-desc {
    font-size: 0.7rem;
    color: var(--text-secondary);
    margin-top: 2px;
}

@media (max-width: 1100px) {
    .hp35-layout {
        grid-template-columns: 1fr;
        height: auto;
        overflow-y: auto;
    }
    .hp35-info-panel {
        order: 2;
    }
    .hp35-calculator-panel {
        order: 1;
    }
    .hp35-trace-panel {
        order: 3;
        max-height: 300px;
    }
}

