from flask import session, jsonify, request, send_from_directory
from app import app, db
from replit_auth import require_login, make_replit_blueprint
from flask_login import current_user
from models import SimulatorState, LandingPageContent
import json
import os
import logging
import bleach

logger = logging.getLogger(__name__)

try:
    replit_bp = make_replit_blueprint()
    app.register_blueprint(replit_bp, url_prefix="/auth")
    auth_enabled = True
    logger.info("Replit Auth enabled")
except Exception as e:
    auth_enabled = False
    logger.warning(f"Replit Auth not available: {e}")

@app.before_request
def make_session_permanent():
    session.permanent = True

@app.after_request
def add_cache_control_headers(response):
    if request.path.endswith('.js') or request.path.endswith('.css'):
        response.headers['Cache-Control'] = 'no-cache, no-store, must-revalidate'
        response.headers['Pragma'] = 'no-cache'
        response.headers['Expires'] = '0'
    return response

@app.route('/ctmm/')
def ctmm_index():
    return send_from_directory('.', 'index.html')

@app.route('/ctmm/<path:path>')
def ctmm_static(path):
    return send_from_directory('.', path)

@app.route('/api/user')
def get_user():
    if current_user.is_authenticated:
        return jsonify({
            'authenticated': True,
            'id': current_user.id,
            'email': current_user.email,
            'first_name': current_user.first_name,
            'last_name': current_user.last_name,
            'profile_image_url': current_user.profile_image_url
        })
    return jsonify({'authenticated': False})

@app.route('/api/state', methods=['GET'])
@require_login
def get_state():
    name = request.args.get('name', 'default')
    state = SimulatorState.query.filter_by(user_id=current_user.id, name=name).first()
    if state:
        return jsonify({
            'found': True,
            'name': state.name,
            'state_data': state.state_data,
            'assembly_code': state.assembly_code,
            'updated_at': state.updated_at.isoformat() if state.updated_at else None
        })
    return jsonify({'found': False})

@app.route('/api/state', methods=['POST'])
@require_login
def save_state():
    data = request.get_json()
    name = data.get('name', 'default')
    state_data = data.get('state_data', '{}')
    assembly_code = data.get('assembly_code', '')

    state = SimulatorState.query.filter_by(user_id=current_user.id, name=name).first()
    if state:
        state.state_data = state_data
        state.assembly_code = assembly_code
    else:
        state = SimulatorState(
            user_id=current_user.id,
            name=name,
            state_data=state_data,
            assembly_code=assembly_code
        )
        db.session.add(state)

    db.session.commit()
    return jsonify({'success': True, 'id': state.id})

@app.route('/api/states', methods=['GET'])
@require_login
def list_states():
    states = SimulatorState.query.filter_by(user_id=current_user.id).all()
    return jsonify({
        'states': [{
            'id': s.id,
            'name': s.name,
            'updated_at': s.updated_at.isoformat() if s.updated_at else None
        } for s in states]
    })

@app.route('/api/state/<int:state_id>', methods=['DELETE'])
@require_login
def delete_state(state_id):
    state = SimulatorState.query.filter_by(id=state_id, user_id=current_user.id).first()
    if state:
        db.session.delete(state)
        db.session.commit()
        return jsonify({'success': True})
    return jsonify({'success': False, 'error': 'State not found'}), 404

def is_development_mode():
    replit_deployment = os.environ.get('REPLIT_DEPLOYMENT')
    if replit_deployment is None:
        replit_dev = os.environ.get('REPLIT_DEV_DOMAIN')
        return replit_dev is not None
    return replit_deployment != '1'

ALLOWED_TAGS = ['h1', 'h2', 'h3', 'h4', 'h5', 'h6', 'p', 'strong', 'em', 'span', 
                'div', 'pre', 'code', 'br', 'a', 'ul', 'ol', 'li', 'i', 'b']
ALLOWED_ATTRS = {
    '*': ['class', 'id', 'title', 'data-section', 'data-tooltip'],
    'a': ['href'],
}
ALLOWED_PROTOCOLS = ['http', 'https', 'mailto']

def sanitize_html(html_content):
    return bleach.clean(
        html_content,
        tags=ALLOWED_TAGS,
        attributes=ALLOWED_ATTRS,
        protocols=ALLOWED_PROTOCOLS,
        strip=True
    )

@app.route('/api/environment')
def get_environment():
    return jsonify({
        'is_development': is_development_mode()
    })

@app.route('/api/landing-content', methods=['GET'])
def get_landing_content():
    contents = LandingPageContent.query.all()
    return jsonify({
        'contents': {c.section_key: c.content for c in contents}
    })

@app.route('/api/landing-content', methods=['POST'])
@require_login
def save_landing_content():
    if not is_development_mode():
        return jsonify({'success': False, 'error': 'Editing disabled in production'}), 403

    data = request.get_json()
    section_key = data.get('section_key')
    content = data.get('content')

    if not section_key or content is None:
        return jsonify({'success': False, 'error': 'Missing section_key or content'}), 400

    sanitized_content = sanitize_html(content)

    existing = LandingPageContent.query.filter_by(section_key=section_key).first()
    if existing:
        existing.content = sanitized_content
        existing.updated_by = current_user.id
    else:
        new_content = LandingPageContent(
            section_key=section_key,
            content=sanitized_content,
            updated_by=current_user.id
        )
        db.session.add(new_content)

    db.session.commit()
    return jsonify({'success': True})

riscv_cap/styles.css.content:
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    font-size: 14px;
    background: #1a1a2e;
    color: #e0e0e0;
    min-height: 100vh;
}

::-webkit-scrollbar {
    width: 8px;
    height: 8px;
}

::-webkit-scrollbar-track {
    background: #1a1a2e;
}

::-webkit-scrollbar-thumb {
    background: #0f3460;
    border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
    background: #00b4d8;
}

.fixed-toolbar {
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    height: 50px;
    z-index: 100;
    background: #16213e;
    border-bottom: 2px solid #0f3460;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 16px;
}

.toolbar-left {
    display: flex;
    align-items: center;
    flex-shrink: 0;
}

.toolbar-title {
    font-size: 1rem;
    font-weight: 700;
    color: #00b4d8;
    letter-spacing: 0.5px;
}

.toolbar-nav {
    display: flex;
    align-items: center;
    gap: 2px;
    flex-shrink: 1;
    min-width: 0;
    overflow-x: auto;
    scrollbar-width: none;
}

.toolbar-nav::-webkit-scrollbar {
    display: none;
}

.toolbar-right {
    display: flex;
    align-items: center;
    gap: 6px;
    flex-shrink: 0;
}

.btn {
    padding: 6px 14px;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 13px;
    transition: all 0.2s;
    font-family: inherit;
}

.btn:hover {
    filter: brightness(1.2);
}

.btn-view {
    background: transparent;
    color: #a0a0a0;
    border-bottom: 2px solid transparent;
    border-radius: 0;
    padding: 14px 12px;
    font-size: 12px;
    white-space: nowrap;
}

.btn-view:hover {
    color: #e0e0e0;
}

.btn-view.active {
    color: #00b4d8;
    border-bottom-color: #00b4d8;
}

.btn-swap-sim {
    padding: 5px 10px;
    background: linear-gradient(135deg, #f59e0b, #d97706);
    color: #1a1a2e;
    border: 1px solid #f59e0b;
    border-radius: 4px;
    font-size: 12px;
    font-weight: 700;
    text-decoration: none;
    white-space: nowrap;
    cursor: pointer;
    transition: all 0.2s;
    margin-left: 8px;
}

.btn-swap-sim:hover {
    background: linear-gradient(135deg, #fbbf24, #f59e0b);
    box-shadow: 0 0 8px rgba(245, 158, 11, 0.4);
    transform: translateY(-1px);
}

.btn-control {
    background: #444;
    color: #e0e0e0;
    padding: 5px 12px;
    font-size: 12px;
}

.btn-control:hover {
    background: #555;
}

.btn-run {
    background: #1b4332;
    color: #4ecca3;
}

.btn-run:hover {
    background: #245a42;
}

.btn-stop {
    background: #3d0000;
    color: #e94560;
}

.btn-stop:hover {
    background: #550000;
}

#btn-step {
    background: #0f3460;
    color: #00b4d8;
}

#btn-step:hover {
    background: #164578;
}

main {
    padding: 60px 16px 16px;
    min-height: calc(100vh - 50px);
}

.view {
    display: none;
    padding-top: 10px;
    min-height: calc(100vh - 80px);
}

.view.active {
    display: block;
}

.panel {
    background: #16213e;
    border-radius: 6px;
    padding: 12px;
    border: 1px solid rgba(15, 52, 96, 0.6);
}

.panel h2 {
    font-size: 0.85rem;
    color: #00b4d8;
    margin-bottom: 10px;
    padding-bottom: 6px;
    border-bottom: 1px solid #0f3460;
}

.panel h3 {
    font-size: 0.8rem;
    color: #f0a500;
    margin-bottom: 8px;
}

.dashboard-grid {
    display: grid;
    grid-template-columns: 60% 40%;
    gap: 12px;
    margin-bottom: 12px;
}

.left-column {
    display: flex;
    flex-direction: column;
    gap: 12px;
}

.pc-display {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    background: #0f3460;
    padding: 6px 14px;
    border-radius: 6px;
    margin-bottom: 10px;
}

.pc-label {
    font-weight: 700;
