    min-width: 60px;
    text-align: right;
}

.status-bar {
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-top: 10px;
    padding: 6px 10px;
    background: rgba(15, 52, 96, 0.3);
    border-radius: 4px;
    font-size: 12px;
}

.boot-status {
    color: #a0a0a0;
}

.step-count {
    color: #a0a0a0;
    font-family: 'Courier New', monospace;
}

.stack-indicators {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    margin-left: 8px;
