.btn-tunnel-notify {
    position: relative;
    background: transparent;
    border: 1px solid #42a5f5;
    color: #42a5f5;
    padding: 4px 10px;
    border-radius: 6px;
    cursor: pointer;
    font-size: 1rem;
    transition: all 0.2s;
    animation: notifyPulse 2s infinite;
}

.btn-tunnel-notify:hover {
    background: rgba(66, 165, 245, 0.15);
    transform: scale(1.05);
}

.tunnel-badge {
    position: absolute;
    top: -6px;
    right: -6px;
    background: #e53935;
    color: #fff;
    font-size: 0.65rem;
    font-weight: 700;
    min-width: 16px;
    height: 16px;
    line-height: 16px;
    border-radius: 50%;
    text-align: center;
    padding: 0 3px;
}

@keyframes notifyPulse {
    0%, 100% { box-shadow: 0 0 0 0 rgba(66, 165, 245, 0.4); }
    50% { box-shadow: 0 0 12px 4px rgba(66, 165, 245, 0.2); }
}

.tunnel-overlay {
    position: fixed;
    top: 0; left: 0; right: 0; bottom: 0;
    background: rgba(0, 0, 0, 0.6);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 9999;
    backdrop-filter: blur(3px);
}

.tunnel-msg-panel {
    background: #1a1a2e;
    border: 1px solid #333;
    border-radius: 12px;
    width: 480px;
    max-width: 95vw;
    max-height: 85vh;
    box-shadow: 0 8px 40px rgba(0, 0, 0, 0.6);
    animation: tunnelMsgAppear 0.3s ease-out;
    display: flex;
    flex-direction: column;
}

@keyframes tunnelMsgAppear {
    from { transform: scale(0.85); opacity: 0; }
    to { transform: scale(1); opacity: 1; }
}

.tunnel-msg-header {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.75rem 1rem;
    border-bottom: 2px solid #42a5f5;
