    background: rgba(66, 165, 245, 0.06);
    letter-spacing: 0.05em;
    font-family: 'Georgia', serif;
    color: #42a5f5;
    word-wrap: break-word;
    overflow-wrap: break-word;
    word-break: break-word;
    hyphens: auto;
    max-width: 100%;
