.tunnel-msg-payload.tunnel-long-msg {
    font-size: 1.1rem;
    letter-spacing: 0;
    line-height: 1.5;
    text-align: left;
    padding: 0.75rem 1rem;
}

.tunnel-msg-flow {
    text-align: center;
    font-size: 0.95rem;
    color: #aaa;
    margin-bottom: 1rem;
    padding: 0.5rem;
}

.tunnel-msg-details {
    display: flex;
    flex-direction: column;
    gap: 0.35rem;
    margin-bottom: 0.75rem;
    padding: 0.75rem;
    background: rgba(255, 255, 255, 0.03);
