    html += `<div class="gt-field gt-perms" style="width:18.75%"><div class="gt-field-label">Permissions</div><div class="gt-field-value">${((cr.word0 >> 2) & 0x3F).toString(2).padStart(6, '0')}</div><div class="gt-field-bits">[7:2]</div></div>`;
